// PROP-042 (2026-05-17): compression-hold-queue telemetry. Read monitor/decisions/compression-hold-queue.json (created lazily by decider when first compression EXP lands), count entries with operator_review_required===true.
let compressionHoldCount = 0;
let oldestCompressionHoldDays = 0;
try{
  const ch = JSON.parse(fs.readFileSync('monitor/decisions/compression-hold-queue.json','utf8'));
  const arr = Array.isArray(ch) ? ch : (ch.entries || ch.items || []);
  const pending = arr.filter(e => e.operator_review_required === true);
  compressionHoldCount = pending.length;
  if (pending.length) {
    const oldestAt = Math.min(...pending.map(e => Date.parse(e.hold_added_at || e.authored_at) || Date.now()));
    oldestCompressionHoldDays = Math.floor((Date.now() - oldestAt) / 86400000);
  }
}catch(_){}
metrics.pending_compression_hold_count = compressionHoldCount;
metrics.oldest_compression_hold_days = oldestCompressionHoldDays;
